const toIso = (value) => {
  const parsed = Date.parse(value || '');
  return Number.isFinite(parsed) ? new Date(parsed).toISOString() : null;
};
const pickBestVariant = (variants) => {
  if (!Array.isArray(variants)) return '';
  const candidates = variants.filter((variant) => /^video\//i.test(variant?.content_type || '') && /^https?:/i.test(variant?.url || ''));
  candidates.sort((a, b) => Number(b?.bitrate || 0) - Number(a?.bitrate || 0));
  return candidates[0]?.url || '';
};
const mediaFromLegacy = (legacy) => {
  const media = legacy?.extended_entities?.media || legacy?.entities?.media || [];
  const imageUrls = [];
  const videoUrls = [];
  const mediaPermalinks = [];
  for (const item of media) {
    if (!item || typeof item !== 'object') continue;
    if (item.type === 'photo' && /^https?:/i.test(item.media_url_https || '')) imageUrls.push(item.media_url_https);
    if ((item.type === 'video' || item.type === 'animated_gif')) {
      const videoUrl = pickBestVariant(item.video_info?.variants);
      if (videoUrl) videoUrls.push(videoUrl);
    }
    if (/^https?:/i.test(item.expanded_url || '')) mediaPermalinks.push(item.expanded_url);
  }
  return {
    image_urls: unique(imageUrls),
    video_urls: unique(videoUrls),
    media_permalink_urls: unique(mediaPermalinks)
