};
const textFromTweet = (tweet) => {
  const noteText = tweet?.note_tweet?.note_tweet_results?.result?.text;
  const legacyText = tweet?.legacy?.full_text;
  return normalize(noteText || legacyText || '');
};
const urlsFromLegacy = (legacy) => unique((legacy?.entities?.urls || []).map((item) => item?.expanded_url || '').filter((href) => /^https?:/i.test(href)));
const findTweetResult = (root, targetId) => {
  const stack = [root];
  const seen = new Set();
  while (stack.length) {
    const current = stack.pop();
    if (!current || typeof current !== 'object') continue;
    if (seen.has(current)) continue;
    seen.add(current);
    const result = current?.result;
    if (result && typeof result === 'object') stack.push(result);
    const tweet = current?.tweet;
    if (tweet && typeof tweet === 'object') stack.push(tweet);
    const itemContentTweet = current?.itemContent?.tweet_results?.result;
    if (itemContentTweet && typeof itemContentTweet === 'object') stack.push(itemContentTweet);
    const legacy = current?.legacy;
    const restId = String(current?.rest_id || current?.id_str || legacy?.id_str || '');
    if (legacy && restId === targetId) return current;
    if (Array.isArray(current)) {
      for (const item of current) stack.push(item);
